import { useState, useEffect } from "react";
import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";

export function PocetnaGosti() {
    const [sobe, setSobe] = useState([]);
    const [filterSlobodne, setFilterSlobodne] = useState(false);
    const [filterTip, setFilterTip] = useState("");
    const [tipoviSoba, setTipoviSoba] = useState([]);

    const [showModal, setShowModal] = useState(false);
    const [izabranaSoba, setIzabranaSoba] = useState(null);
    const [datumPrijave, setDatumPrijave] = useState("");
    const [datumOdjave, setDatumOdjave] = useState("");
    const [brojOsoba, setBrojOsoba] = useState(1);

    const userId = parseInt(document.cookie.split("userId=")[1]?.split(";")[0]); // trenutni gost
    const izracunajUkupno = () => {
        if (!datumPrijave || !datumOdjave) return 0;
        const start = new Date(datumPrijave);
        const end = new Date(datumOdjave);
        const diffTime = end - start;
        const brojNoci = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        const cenaPoNoci = izabranaSoba?.tipSobe?.cenaPoNoci || 0;
        return cenaPoNoci * brojNoci * brojOsoba;
    };



    // Učitavanje svih soba
    useEffect(() => {
        fetch("http://localhost:8080/rooms/all")
            .then((res) => res.json())
            .then((data) => {
                if (data?.data?.values) setSobe(data.data.values);

                // Ekstraktujemo tipove soba iz podataka
                const tipovi = Array.from(new Set(data.data.values.map(s => s.tipSobe?.naziv))).filter(Boolean);
                setTipoviSoba(tipovi);
            })
            .catch((err) => console.error("Greška pri učitavanju soba:", err));
    }, []);

    // Primena filtera
    const filtriraneSobe = sobe.filter((soba) => {
        const slobodna = !filterSlobodne || soba.dostupna;
        const tip = !filterTip || (soba.tipSobe?.naziv === filterTip);
        return slobodna && tip;
    });

    // Otvori modal za izabranu sobu
    const handleSobaClick = (soba) => {
        if(!soba.dostupna){
            alert("Soba je nedostupna!");
            return;
        }
        setIzabranaSoba(soba);
        setDatumPrijave("");
        setDatumOdjave("");
        setBrojOsoba(1);
        setShowModal(true);
    };

    // Slanje zahteva
    const handlePosaljiZahtev = async () => {
      
        if (!datumPrijave || !datumOdjave) {
            alert("Unesite datume prijave i odjave.");
            return;
        }
              if(!userId || isNaN(userId)){
            alert("Morate biti ulogovani!");
            return;
        }
        const rezervacijaDTO = {
            datumPrijave,
            datumOdjave,
            brojOsoba,
            statusRezervacije: "PENDING", // <--- ovde
            gost: { idGost: userId },
            soba: { idSoba: izabranaSoba.idSoba },
            recepcionar: null,
            ukupanIznos: izracunajUkupno(),
            datumKreiranja: new Date().toISOString().split("T")[0]
        };

        try {
            const res = await fetch("http://localhost:8080/reservations/add", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(rezervacijaDTO)
            });

            const data = await res.json();
            if (res.ok) {
                alert("Zahtev za rezervaciju je poslat!");
                setShowModal(false);
            } else {
                alert("Neuspešno slanje zahteva!");
            }
        } catch (err) {
            console.error(err);
            alert("Greška pri komunikaciji sa serverom.");
        }

    };

    return (
        <>
            <NavBar />
            <div
                style={{
                    backgroundImage: `url(${pattern})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                    minHeight: "100vh",
                    padding: "40px",
                }}
            >
                <h2
                    style={{
                        textAlign: "center",
                        color: "white",
                        backgroundColor: "rgba(215, 96, 255, 0.6)",
                        padding: "15px 30px",
                        borderRadius: "10px",
                        display: "inline-block",
                    }}
                >
                    Pregled soba
                </h2>

                {/* Filter */}
                <div style={{ margin: "20px 0", display: "flex", gap: "20px", justifyContent: "center" }}>
                   
                    <label style={{fontSize:"15px",marginTop:"15px"}}>
                         <input
                            type="checkbox"
                            checked={filterSlobodne}
                            onChange={() => setFilterSlobodne(!filterSlobodne)}
                        />{" "}
                        Prikaži samo slobodne
                    </label>
                    

                    <select value={filterTip} style={{width:"250px",height:"40px",textAlign:"center",borderRadius:"10px",fontSize:"15px"}} onChange={(e) => setFilterTip(e.target.value)}>
                        <option value="">Svi tipovi soba</option>
                        {tipoviSoba.map((tip, idx) => (
                            <option key={idx} value={tip}>{tip}</option>
                        ))}
                    </select>
                </div>

                {/* Lista soba */}
                <div style={{ display: "flex", flexWrap: "wrap", gap: "20px", justifyContent: "center" }}>
                    {filtriraneSobe.map((soba) => (
                        <div
                            key={soba.idSoba}
                            style={{
                                backgroundColor: "rgba(255,255,255,0.9)",
                                width: "250px",
                                borderRadius: "15px",
                                padding: "15px",
                                textAlign: "center",
                                boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
                                cursor: "pointer"
                            }}
                            onClick={() => handleSobaClick(soba)}
                        >
                            {soba.slika && (
                                <img
                                    src={`http://localhost:8080/uploads/${soba.slika.split("/").pop()}`}
                                    alt="Slika sobe"
                                    style={{ width: "100%", height: "150px", borderRadius: "10px", objectFit: "cover" }}
                                />
                            )}
                            <h3>{soba.naziv}</h3>
                            <p>Broj sobe: {soba.brojSobe}</p>
                            <p>Tip sobe: {soba.tipSobe?.naziv || "Nepoznat"}</p>
                            <p>Cena po noći: {soba.tipSobe?.cenaPoNoci || 0} RSD</p>
                            <p>Status: {soba.dostupna ? "Dostupna" : "Nedostupna"}</p>
                        </div>
                    ))}
                </div>
            </div>

            {/* MODAL ZA ZAHVAT */}
            {showModal && izabranaSoba && (
                <div style={{
                    position: "fixed", top: 0, left: 0, width: "100%", height: "100%",
                    backgroundColor: "rgba(0,0,0,0.6)", display: "flex",
                    justifyContent: "center", alignItems: "center"
                }}>
                    <div style={{ backgroundColor: "white", padding: "20px", borderRadius: "10px", width: "400px" }}>
                        <h3>Zahtev za rezervaciju - {izabranaSoba.naziv}</h3>

                        <label>Datum prijave:</label>
                        <input type="date" value={datumPrijave} onChange={(e) => setDatumPrijave(e.target.value)} style={{ width: "100%", marginBottom: "10px" }} />

                        <label>Datum odjave:</label>
                        <input type="date" value={datumOdjave} onChange={(e) => setDatumOdjave(e.target.value)} style={{ width: "100%", marginBottom: "10px" }} />

                        <label>Broj osoba:</label>
                        <input type="number" value={brojOsoba} min={1} onChange={(e) => setBrojOsoba(parseInt(e.target.value))} style={{ width: "100%", marginBottom: "10px" }} />

                        <div style={{ display: "flex", justifyContent: "flex-end", gap: "10px" }}>
                            <button onClick={() => setShowModal(false)} style={{ backgroundColor: "gray", color: "white", border: "none", borderRadius: "5px", padding: "5px 10px" }}>Otkaži</button>
                           <button onClick={handlePosaljiZahtev} style={{ backgroundColor: "purple", color: "white", border: "none", borderRadius: "5px", padding: "5px 10px" }}>Pošalji zahtev</button>
                        </div>
                    </div>
                </div>
            )}

            <Footer />
        </>
    );
}
